import { useEffect } from "react"
import { FetchApi } from "../../../Controller/FetchApi";

export default function TelaBrinquedos(){
    useEffect(() => {
        async function listarBrinquedos(){
            console.log(await FetchApi.consultaGet('/brinquedos'));
        }
        listarBrinquedos();
        
    }, []);

    return(
        <div className="row">
            Lista de Brinquedos
        </div>
    )
}
